import React, { useEffect, useState } from "react";
import axios from "axios";
import { useNavigate } from "react-router-dom";
import EditProfile from "../users/EditProfile";

export default function UsrProfile() {
  const navigate = useNavigate();

  const [user, setUser] = useState(null);
  const [showEditProfile, setShowEditProfile] = useState(false);

  useEffect(() => {
    const stored = JSON.parse(localStorage.getItem("user") || "{}");

    if (!stored?.email) return;

    axios
      .get(`http://localhost:8086/user/profile?email=${stored.email}`)
      .then((res) => setUser(res.data))
      .catch(console.log);
  }, []);

  if (!user) {
    return (
      <div className="min-h-screen flex items-center justify-center bg-gradient-to-br from-indigo-200 via-purple-200 to-pink-200">
        Loading profile...
      </div>
    );
  }

  return (
    <div className="min-h-screen flex items-center justify-center p-6 bg-gradient-to-br from-indigo-200 via-purple-200 to-pink-200">

      {showEditProfile && (
        <EditProfile
          user={user}
          closeModal={() => setShowEditProfile(false)}
          onUpdated={(u) => setUser(u)}
        />
      )}

      <div className="backdrop-blur-xl bg-white/30 p-8 rounded-2xl w-full max-w-md">

        <div className="text-center">
          <img
            src={user.profileImage || `https://ui-avatars.com/api/?name=${user.username}`}
            alt="profile"
            className="w-28 h-28 rounded-full mx-auto"
          />

          <h2 className="text-xl font-bold mt-3">{user.name}</h2>
          <p>{user.email}</p>
        </div>

        <button
          onClick={() => setShowEditProfile(true)}
          className="w-full mt-6 bg-indigo-500 text-white py-2 rounded-lg"
        >
          Edit Profile
        </button>

        <button
          onClick={() => {
            localStorage.clear();
            navigate("/");
            window.location.reload();
          }}
          className="w-full mt-3 bg-red-500 text-white py-2 rounded-lg"
        >
          Logout
        </button>

      </div>
    </div>
  );
}
